const body = $json.body || $json || {};
const clean = (value, fallback = '') => String(value ?? fallback).trim();
const numeric = (value, fallback, min, max) => Math.max(min, Math.min(max, Number(value ?? fallback) || fallback));
const focusAreas = Array.isArray(body.focusAreas) && body.focusAreas.length
  ? body.focusAreas.map((item) => clean(item)).filter(Boolean)
  : ['runtime', 'automacao', 'qa', 'docs'];
const constraints = Array.isArray(body.constraints)
  ? body.constraints.map((item) => clean(item)).filter(Boolean)
  : ['safe-mode', 'sem edicao automatica de codigo', 'Slack + JSON como saida'];
return [{ json: {
  objective: clean(body.objective, 'Preparar avancos seguros para o proximo ciclo do Odessa enquanto Lucas descansa'),
  durationMinutes: numeric(body.durationMinutes, 90, 15, 480),
  focusAreas,
  maxAdvancements: numeric(body.maxAdvancements, 4, 1, 8),
  requestedBy: clean(body.requestedBy, 'Lucas'),
  constraints,
  targetChannel: clean(body.targetChannel, 'odessa-roadmap').replace(/^#/, '')
} }];

const response = $json;
const nightShift = response.nightShift || {};
const channel = String(nightShift.slackRoute || 'odessa-roadmap').replace(/^#/, '');
const advancements = Array.isArray(nightShift.advancements) ? nightShift.advancements : [];
const advancementText = advancements.length
  ? advancements.map((item) => `- *${item.id || 'ODS-NS'}* ${item.title || 'Avanco'} (${item.area || 'produto'})\n  ${item.why || ''}\n  Handoff: ${item.handoffPrompt || 'Revisar e executar com supervisao.'}`).join('\n')
  : '- Nenhum avanco gerado';
const risks = Array.isArray(nightShift.risks) ? nightShift.risks.map((risk) => `- ${risk}`).join('\n') : '- Sem riscos listados';
const text = `*${nightShift.title || 'Odessa Night Shift'}*\n${nightShift.summary || ''}\n\n*Avancos preparados*\n${advancementText}\n\n*Riscos*\n${risks}\n\n*Briefing de retorno*\n${nightShift.morningBrief || 'Revisar pacote e escolher a primeira tarefa.'}`;
const slackMessage = {
  channel: `#${channel}`,
  text,
  blocks: [
    { type: 'section', text: { type: 'mrkdwn', text: `*${nightShift.title || 'Odessa Night Shift'}*\n${nightShift.summary || ''}` } },
    { type: 'section', text: { type: 'mrkdwn', text: `*Avancos preparados*\n${advancementText}` } },
    { type: 'section', text: { type: 'mrkdwn', text: `*Briefing de retorno*\n${nightShift.morningBrief || 'Revisar pacote e escolher a primeira tarefa.'}` } }
  ]
};
return [{ json: { ok: response.ok !== false, nightShift, slackMessage } }];

const webhookUrl = String($env.N8N_SLACK_WEBHOOK_URL || $env.SLACK_WEBHOOK_URL || '').trim();
const slackDispatch = { configured: Boolean(webhookUrl), sent: false, status: null, error: null };
if (webhookUrl) {
  try {
    const response = await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text: $json.slackMessage.text, blocks: $json.slackMessage.blocks })
    });
    slackDispatch.sent = response.ok;
    slackDispatch.status = response.status;
    if (!response.ok) slackDispatch.error = await response.text();
  } catch (error) {
    slackDispatch.error = error.message || 'Slack webhook failed';
  }
}
return [{ json: { ...$json, slackDispatch } }];

const nightShift = $json.nightShift || {};
const createdAt = new Date().toISOString();
const idDate = createdAt.slice(0, 19).replace(/[:T]/g, '-');
const artifact = {
  nightShiftId: `ods-night-shift-${idDate}`,
  createdAt,
  mode: 'safe_advances',
  nightShift,
  slack: $json.slackMessage,
  slackDispatch: $json.slackDispatch || { configured: false, sent: false },
  resumeChecklist: [
    'Ler o morningBrief',
    'Escolher um avanco ODS-NS para executar',
    'Validar riscos antes de editar codigo',
    'Registrar resultado no Slack/QA'
  ]
};
return [{ json: { ok: true, nightShift, slackMessage: $json.slackMessage, slackDispatch: $json.slackDispatch, artifact } }];
